window.__QUIZ_DATA__=[{"id":"objective>Geography>2018>1","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of ALADE DISTRICT and use it to answer this question    What is the scale of the map?","images":["data:image/png;base64,"],"options":{"A":"1 : 50,000","B":"1 : 100,000","C":"1 : 150, 000","D":"1 : 200,000"},"answer":"D","explanation":"1 cm is equivalent to 2km   \u21d2 1 cm : 2 km (Place your ruler on the scale beneath the map)   0.01m : 2000m  Multiply through by 100   1 m : 200,000 m   \u21d2 The scale of the map is 1:200,000","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>2","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of ALADE DISTRICT and use it to answer this question  The highest contour on the map is","images":["data:image/png;base64,"],"options":{"A":"800 m","B":"750 m","C":"730 m","D":"700m"},"answer":"B","explanation":"The highest contour of the map is showing 750 m. Others are not correct","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>3","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of ALADE DISTRICT and use it to answer this question  Which area on the map can the trigonometrical station be found?","images":["data:image/png;base64,"],"options":{"A":"North-east","B":"South-east","C":"North-west","D":"South-west"},"answer":"B","explanation":"The trigonometrical station is located in the South-east on the map   Note that a trigonometrical station is also called a triangular station.   It is represented with","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>4","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of ALADE DISTRICT and use it to answer this question  What is the approximate length of the railway line on the map?","images":["data:image/png;base64,"],"options":{"A":"29km","B":"37km","C":"40km","D":"45km"},"answer":"B","explanation":"The approximate length of the rail way is 18.5 cm which is equal to 37km according to the scale of the map","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>5","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of ALADE DISTRICT and use it to answer this question  R. Kafue takes its source from a","images":["data:image/png;base64,"],"options":{"A":"plateau","B":"ridge","C":"knoll","D":"conical hill"},"answer":"B","explanation":"R. Kafue takes its source from a ridge and not other options listed.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>6","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of ALADE DISTRICT and use it to answer this question  The feature marked P is a","images":["data:image/png;base64,"],"options":{"A":"mountain","B":"spur","C":"knoll","D":"valley"},"answer":"C","explanation":"The feature marked P is knoll, i.e a small hill or mound","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>7","subject":"Geography","year":"2018","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Study the map of ALADE DISTRICT and use it to answer this question  The northern part of the map is suitable for","images":["data:image/png;base64,"],"options":{"A":"mining","B":"trading","C":"lumbering","D":"farming"},"answer":"C","explanation":"The northern part of the map is suitable for lumbering since it has a lot of trees","marks":"1","difficulty":"3"},{"id":"objective>Geography>2018>8","subject":"Geography","year":"2018","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Study the map of ALADE DISTRICT and use it to answer this question  What type of settlement is ALADE?","images":["data:image/png;base64,"],"options":{"A":"Nodal","B":"Coastal","C":"Dry Valley","D":"Linear"},"answer":"A","explanation":"ALADE is a nodal settlement. A nodal settlement refers to buildings that are arranged around a town with divergent or convergent roads.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>9","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of ALADE DISTRICT and use it to answer this question  What is the bearing of the trigonometrical station from  Ilo  on the map?","images":["data:image/png;base64,"],"options":{"A":"168\u00b0","B":"178\u00b0","C":"190\u00b0","D":"200\u00b0"},"answer":"B","explanation":"NOTE: \u2205 is closed to 180o  The bearing of the trigonometrical station from Ilo is 178o","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>10","subject":"Geography","year":"2018","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Study the map of ALADE DISTRICT and use it to answer this question  The most important settlement in the area is","images":["data:image/png;base64,"],"options":{"A":"Ilo","B":"Ilapo","C":"Aso","D":"ALADE"},"answer":"D","explanation":"The most important settlement in the area is ALADE","marks":"1","difficulty":"1"},{"id":"objective>Geography>2018>11","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Use the climatic data below to answer this question  MONTHJan.Feb.Mar.Apr.MayJuneJulyAug.Sept.Oct.Nov.DecTemperature (\u00b0C)262626262627272828282727Rainfall (mm)35501041391952282482432452509155    The annual range of temperature for the station is","images":[],"options":{"A":"1\u00b0C","B":"2\u00b0C","C":"22\u00b0C","D":"28\u00b0C"},"answer":"B","explanation":"The annual range of temperature for the station is 28oc - 26oc = 2oc  N.B: Range = Highest - Lowest","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>12","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Use the climatic data below to answer this question  MONTHJan.Feb.Mar.Apr.MayJuneJulyAug.Sept.Oct.Nov.DecTemperature (\u00b0C)262626262627272828282727Rainfall (mm)35501041391952282482432452509155  From which climatic region were the data taken?","images":[],"options":{"A":"Desert","B":"Mediterranean","C":"Equatorial","D":"Tropical Monsoon"},"answer":"C","explanation":"The climatic data shows high temperatures throughout the year and high rainfall, especially from April to October. This is characteristic of an Equatorial climate, which is hot and wet all year round. The other options (Desert, Mediterranean, Tropical Monsoon) do not match this pattern. A desert climate would have low rainfall, a Mediterranean climate would have a dry summer and wet winter, and a Tropical Monsoon climate would have a distinct dry season, which is not evident in the data.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2018>13","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Use the climatic data below to answer this question  MONTHJan.Feb.Mar.Apr.MayJuneJulyAug.Sept.Oct.Nov.DecTemperature (\u00b0C)262626262627272828282727Rainfall (mm)35501041391952282482432452509155  Which of the following towns experiences the type of climate represented in the table?","images":[],"options":{"A":"Gao (Mali)","B":"Cairo (Egypt)","C":"Warri (Nigeria)","D":"London (England)"},"answer":"C","explanation":"Warri (Nigeria) has an equatorial climate   N.B: Southern Nigeria is equatorial, Central Nigeria is tropical, while the northern region of the country is arid.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>14","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Use the climatic data below to answer this question  MONTHJan.Feb.Mar.Apr.MayJuneJulyAug.Sept.Oct.Nov.DecTemperature (\u00b0C)262626262627272828282727Rainfall (mm)35501041391952282482432452509155  What is the MEAN temperature from July to December?","images":[],"options":{"A":"16.5\u00b0C","B":"17.2\u00b0C","C":"27.5\u00b0C","D":"28.0\u00b0C"},"answer":"C","explanation":"Mean = \u2211 x /n  --------- * : mean = Sum of values/no. of values    \u2234Mean temperatureFrom July to December=27+28+28+28+27+276","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>15","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"In Koppen's Classification of climates, Cs, refers to","images":[],"options":{"A":"Steppe","B":"Mediterranean","C":"Tropical Monsoon","D":"Tropical Continental"},"answer":"B","explanation":"In Koppen's Classification of climates, Cs refers to Mediterranean climate. The 'C' represents the temperate climates, and the 's' stands for dry summer. Mediterranean climate is characterized by dry summers and mild, wet winters.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2018>16","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following features is associated with river capture?","images":[],"options":{"A":"Delta","B":"Meander","C":"Levee","D":"Wind gap"},"answer":"D","explanation":"The following features may be associated with river capture:  - Beheaded stream/captured river   - Pirate stream   - Point of incision   - Wind gap/dry river valley   - Elbow of capture","marks":"1","difficulty":"3"},{"id":"objective>Geography>2018>17","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Volcanoes that have erupted before and show signs of possible eruption again are said to be","images":[],"options":{"A":"weak","B":"extinct","C":"dormant","D":"ongoing"},"answer":"C","explanation":"A dormant volcano is used to refer to those that are capable of erupting and will probably erupt again in the future, but hasn't had an eruption for a very long time.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>18","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"In the northern hemisphere, summer solstice is experienced on","images":[],"options":{"A":"September 22","B":"June 21","C":"December 22","D":"March 21"},"answer":"B","explanation":"In the northern hemisphere, summer solstice is experienced on June 21  N.B: The longest day of the year starts on June 21","marks":"1","difficulty":"1"},{"id":"objective>Geography>2018>19","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"A community of plans and animals living in harmony within the same physical environment is referred to as","images":[],"options":{"A":"environmental interaction","B":"terrestrial biocycle","C":"ecosystem","D":"biosphere"},"answer":"C","explanation":"A community of plants and animals living in harmony within the same physical environment is referred to as an ecosystem. An ecosystem includes all of the living things (plants, animals and organisms) in a given area, interacting with each other, and also with their non-living environments (weather, earth, sun, soil, climate, atmosphere).","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>20","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Sea breeze is most effective at","images":[],"options":{"A":"winter","B":"day time","C":"summer","D":"night time"},"answer":"B","explanation":"Sea breeze is most effective at day time. Sea breeze or onshore breeze is any wind that blows from a large body of water towards or on a landmass.     It should be noted that sea breeze is a local wind system characterized by a flow from sea to land during the day .","marks":"1","difficulty":"1"},{"id":"objective>Geography>2018>21","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The nearest planet to the sun is","images":[],"options":{"A":"Jupiter","B":"Saturn","C":"Mercury","D":"Earth"},"answer":"C","explanation":"Mercury is the nearest planet to the sun. It is the smallest planet in our solar system and closest to the sun. Its average distance from the sun is less than 60 million km.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2018>22","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The type of rain mostly experienced within the tropics is","images":[],"options":{"A":"fog","B":"relief","C":"frontal","D":"convectional"},"answer":"D","explanation":"The type of rain mostly experienced within the tropics is convectional rain. This type of rain occurs when the sun's heat causes the earth's surface to warm up, causing the air above it to heat up and rise, leading to the formation of clouds and rain. This process is known as convection.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>23","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"A feature commonly found in the youthful stage of a river is","images":[],"options":{"A":"Levee","B":"Meander","C":"Ox-bow lake","D":"Interlocking spurs"},"answer":"D","explanation":"In the youthful stage of the river, such features as small lakes, rapids and inter locking spurs are frequently found","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>24","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following is not a characteristic of Wadis?","images":[],"options":{"A":"They are river channels","B":"They occur in tropical areas","C":"They hold permanent streams","D":"They have steep craggy walls"},"answer":"C","explanation":"Wadis do not hold permanent streams. Others are characteristics.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2018>25","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Stalactites and stalagmites are associated with which type of the following rocks?","images":[],"options":{"A":"Granite","B":"Sandstone","C":"Limestone","D":"Basalt"},"answer":"C","explanation":"Stalactites and stalagmites are formations that occur in limestone caves due to the deposition of calcium carbonate and other minerals.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>26","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"What is the time in Accra at longitude 0\u00b0 when the local time at longitude 45\u00b0W is 12 noon?","images":[],"options":{"A":"3.00pm","B":"5.00pm","C":"7.00pm","D":"9.00pm"},"answer":"A","explanation":"Longitude difference = 45o   N.B: 15o = 1 hour   \u21d2 45o = 3 hours     Since Accra is at the equator and the place/location is on the West, we are going to add 3 hours to 12 noon to get the local time in Accra, i.e. 3pm.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2018>27","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"What is the distance between two places on the surface of the Earth which are located 8\u00b0N and 10*deg8S on the same longitude?","images":[],"options":{"A":"1,011km","B":"1,998km","C":"10,101km","D":"17,770km"},"answer":"B","explanation":"Parameters given:  Location x : 8il   Location y 10o S  Latitudinal difference = 8o to 10o = 18o   They are on the same longitude (Note that each meridian is a great circle)   \u21d2Distance=\u03b8360x2\u03c0R  =18360x2x227x6370    = 2002 km","marks":"1","difficulty":"3"},{"id":"objective>Geography>2018>28","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Coastal deposition results in the formation of","images":[],"options":{"A":"stack","B":"arch","C":"pillar","D":"beach"},"answer":"D","explanation":"Coastal deposition results in the formation of a beach. Coastal deposition is the process by which the sea drops or deposits material. This can include sand, sediment and shingle, which can build up to form a beach.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>29","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following pairs of elements are found in the core of the Earth?","images":[],"options":{"A":"Iron and silicon","B":"Iron and nickel","C":"Iron and calcium","D":"Iron and magnesium"},"answer":"B","explanation":"The outer core of the earth is about 1400 miles thick, and it's made mostly of a combination (called an alloy) of iron and nickel, along with small amounts of other dense elements like gold, platinum and Uranium.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>30","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"In which of the following layers in the atmosphere does temperature increases with altitude?","images":[],"options":{"A":"Troposphere","B":"Ionosphere","C":"Stratosphere","D":"Exosphere"},"answer":"C","explanation":"In the stratosphere, the atmospheric pressure increases with altitude.   Note that normally, atmospheric pressure decreases with altitude (height).   Also, note that temperature begins to shift as altitude increases because of the presence of the ozone layer.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>31","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Relief rainfall is mostly associated with","images":[],"options":{"A":"lowlands","B":"peneplains","C":"highlands","D":"deserts"},"answer":"C","explanation":"Relief rainfall is mostly associated with highlands. This type of rainfall occurs when air is forced to rise over a physical barrier such as a mountain range. As the air rises, it cools and condenses, forming clouds and resulting in rainfall.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>32","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"The extent of coastal erosion depends on the","images":[],"options":{"A":"amount of fresh water supplied by tributaries","B":"depth of ocean water","C":"salinity of the ocean","D":"nature of the waves"},"answer":"D","explanation":"The extent of coastal erosion depends on the nature of the waves. Stronger waves with higher energy will cause more erosion. Other factors such as the geological structure of the coast and human activities can also influence the rate of coastal erosion.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>33","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The envelope of gases surrounding the Earth's crust is called","images":[],"options":{"A":"hydrosphere","B":"barysphere","C":"atmosphere","D":"lithosphere"},"answer":"C","explanation":"The envelope of gases surrounding the Earth's crust is called the atmosphere. The atmosphere is a layer of gases held in place by Earth's gravity. It is made up primarily of nitrogen (78%) and oxygen (21%), with small amounts of other gases such as argon and carbon dioxide. It protects life on Earth by absorbing ultraviolet solar radiation and reducing temperature extremes between day and night.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2018>34","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Carbonaceous type  of sedimentary rocks are made from","images":[],"options":{"A":"remains of dead animals","B":"vegetative matter","C":"molten magma","D":"living plants and animals"},"answer":"B","explanation":"Carbonaceous type of sedimentary rocks are made from vegetative matter. These rocks are formed from the accumulation and consolidation of plant material, usually in swamp conditions where the lack of oxygen slows decay. Over time, the plant material is transformed into coal through the process of carbonization.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>35","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Autotrophs, heterotrophs and decomposers are associated with","images":[],"options":{"A":"Vegetation","B":"Climate","C":"Ecosystem","D":"Geology"},"answer":"C","explanation":"Autotrophs (green plants), heterotrophs (Animals) and decomposers (fungi and bacteria) are associated with the ecosystem","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>36","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following pairs of rocks is not correctly shown?","images":[],"options":{"A":"clay \u2192 slate","B":"limestone \u2192 marble","C":"sandstone \u2192 quartzite","D":"shale \u2192 graphite"},"answer":"D","explanation":"Shale does not metamorphose into graphite. Shale, under heat and pressure, can turn into slate, phyllite, schist or gneiss, but not graphite. Graphite is a form of carbon and is not a metamorphic form of shale.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2018>37","subject":"Geography","year":"2018","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Cold currents can also cause","images":[],"options":{"A":"rise in tide","B":"rise in temperature of the area","C":"sea level to rise","D":"fogs instead of actual rain"},"answer":"D","explanation":"Cold currents can cause fogs instead of actual rain. This is because cold currents cool the air above them. When this cool air comes into contact with warmer air, it can cause condensation and fog. Cold currents do not cause a rise in tide, temperature, or sea level.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>38","subject":"Geography","year":"2018","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"The most predominant occupation of most of the population of West African countries is","images":[],"options":{"A":"farming","B":"fishing","C":"mining","D":"teaching"},"answer":"A","explanation":"The most predominant occupation of most of the population of West African countries is farming. Agriculture is a major economic activity in many West African countries, with a large portion of the population engaged in subsistence farming.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2018>39","subject":"Geography","year":"2018","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Which of the following is not a characteristic of subsistence farming?","images":[],"options":{"A":"The produce is mainly for home consumption","B":"It is capital intensive","C":"Simple farming tools are used","D":"It is labour intensive"},"answer":"B","explanation":"Subsistence farming is a type of farming in which nearly all of the crops or livestock raised are used to maintain the farmer and the farmer's family, leaving little, if any, surplus for sale or trade. It is not capital intensive, rather it is labour intensive and uses simple farming tools. Capital intensive refers to industries that require a large amount of capital to produce a good or service, which is not the case for subsistence farming.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>40","subject":"Geography","year":"2018","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Trans-continental highways link up","images":[],"options":{"A":"mining cities","B":"countries in a continent","C":"state headquarters","D":"local settlements"},"answer":"B","explanation":"Trans-continental highways are major highways that cross or span more than one continent. They are designed to connect countries within a continent, not just cities or local settlements. Therefore, the correct answer is 'countries in a continent'.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2018>41","subject":"Geography","year":"2018","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Heavy industries require","images":[],"options":{"A":"mostly coal to run them","B":"cheap raw materials as inputs","C":"generators only as source of electricity","D":"large capital to set up"},"answer":"D","explanation":"Heavy industries such as steel, shipbuilding, and car manufacturing require a large amount of capital to set up due to the cost of machinery, infrastructure, and raw materials. While they may also require coal or other energy sources, and cheap raw materials can be beneficial, the defining characteristic is the large capital requirement.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>42","subject":"Geography","year":"2018","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following is likely to make petroleum drilling unimportant?","images":[],"options":{"A":"Depletion of reserves","B":"Adequate capital","C":"Adequate skilled labour","D":"Good management"},"answer":"A","explanation":"The depletion of reserves is the most likely factor to make petroleum drilling unimportant. Petroleum is a non-renewable resource, meaning it doesn't replenish within a human lifespan. Once the reserves are depleted, there will be no more petroleum to drill, making the process unimportant.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2018>43","subject":"Geography","year":"2018","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following statements most apply for solar energy production in Tropical Africa?","images":[],"options":{"A":"Generated without cost","B":"Imported from Europe","C":"Produced in higher latitudes","D":"Cheap and readily accessible"},"answer":"D","explanation":"Solar energy production in Tropical Africa is cheap and readily accessible. This is because Africa, being on the equator, receives a high amount of sunlight throughout the year. This makes it an ideal location for solar energy production. Solar energy is also cheap because once the solar panels are installed, the sunlight, which is the source of the energy, is free.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2018>44","subject":"Geography","year":"2018","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"They are headquarters of governments and we usually capital cities. This best describes","images":[],"options":{"A":"market towns","B":"administrative towns","C":"educational towns","D":"mining towns"},"answer":"B","explanation":"The statement best describes administrative towns. Administrative towns are usually the headquarters of governments and are often capital cities. They are the centers of administrative activities where government offices and institutions are located.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2018>45","subject":"Geography","year":"2018","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"One of the usefulness of import tariff on imported goods is the","images":[],"options":{"A":"encouragement of importation","B":"multiplication of foreign goods","C":"protection of infant industries","D":"saving of money"},"answer":"B","explanation":"One of the usefulness of import tariff on imported goods is the multiplication of foreign goods","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>46","subject":"Geography","year":"2018","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Textile industries are located","images":[],"options":{"A":"near the market","B":"where water resource is scare","C":"in wide plains","D":"near sources of raw materials"},"answer":"A","explanation":"Textile industries are usually located near the markets","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>47","subject":"Geography","year":"2018","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following factors is unique for the development of the aircraft industry in California?","images":[],"options":{"A":"Availability of cheap labour","B":"The peaceful political atmosphere","C":"The government limited support","D":"Clear sky which favours testing of aircrafts"},"answer":"A","explanation":"Availability of cheap labour is unique for the development of the aircraft industry in California","marks":"1","difficulty":"3"},{"id":"objective>Geography>2018>48","subject":"Geography","year":"2018","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"The ranking of settlements into rural and urban is mostly based on","images":[],"options":{"A":"location","B":"size","C":"pattern","D":"population"},"answer":"C","explanation":"The ranking of settlement into rural and urban is mostly based on pattern.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2018>49","subject":"Geography","year":"2018","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"All the following agricultural practices are intensive farming techniques except","images":[],"options":{"A":"land rotation","B":"crop rotation","C":"mixed farming","D":"market gardening"},"answer":"A","explanation":"Land rotation is not an intensive farming technique. Intensive farming techniques are characterized by a high level of inputs and farming practices per unit of agricultural land area. This includes practices like crop rotation, mixed farming, and market gardening. Land rotation, on the other hand, involves changing the use of land from one purpose to another, which is not necessarily an intensive practice.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2018>50","subject":"Geography","year":"2018","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Natural increase in population means excess of","images":[],"options":{"A":"emigration over immigration","B":"immigration over emigration","C":"deaths over births","D":"births over deaths."},"answer":"D","explanation":"Natural increase in population refers to the excess of births over deaths. It is the difference between the number of live births and the number of deaths during the year. If the number of births is greater than the number of deaths, the population increases naturally.","marks":"1","difficulty":"1"}];